/* Background thread function for loading files */
static void file_load_thread_func(void *arg)
{
    EPUB_DEBUG("=== Thread started, arg=%p ===", arg);
    
    load_task_data_t *task = (load_task_data_t *)arg;
    
    if (!task) {
        EPUB_DEBUG("ERROR: Invalid task data");
        s_is_loading = false;
        return;
    }
    
    EPUB_DEBUG("Task data valid, filepath=%s, type=%d", task->full_path, task->file_type);
    EPUB_DEBUG("Container=%p, cancel_flag=%d", task->container, s_cancel_loading);
    
    ui_ebook_reader_t *reader = NULL;
    
    /* Check if loading was cancelled */
    if (s_cancel_loading) {
        EPUB_DEBUG("Loading cancelled before start");
        goto cleanup;
    }
    
    EPUB_DEBUG("Starting ui_ebook_reader_init...");
    
    /* ⚠️ TIME-CONSUMING OPERATION (1-5 seconds for EPUB extraction)
     * No LVGL lock needed here - we're in a background thread
     */
    if (task->file_type == UI_FS_FILE_TYPE_FILE_EPUB || 
        task->file_type == UI_FS_FILE_TYPE_FILE_TEXT) {
        
        /* Check cancellation before starting */
        if (s_cancel_loading) {
            EPUB_DEBUG("Loading cancelled");
            goto cleanup;
        }
        
        EPUB_DEBUG("Calling ui_ebook_reader_init with path: %s", task->full_path);
        
        /* Initialize ebook reader (this extracts ZIP, parses XML, etc.) */
        reader = ui_ebook_reader_init(task->full_path, task->container);
        
        EPUB_DEBUG("ui_ebook_reader_init returned: %p", reader);
        
        if (reader) {
            EPUB_DEBUG("✅ Reader initialized successfully!");
        } else {
            EPUB_DEBUG("❌ Reader initialization failed (returned NULL)");
        }
    }
    
cleanup:
    EPUB_DEBUG("Entering cleanup, reader=%p", reader);
    EPUB_DEBUG("About to call callback...");
    
    /* Notify completion via callback */
    on_file_loaded_callback(reader, task->file_type);
    
    EPUB_DEBUG("After callback - callback executed successfully");
    
    /* Cleanup */
    tal_free(task);
    s_is_loading = false;
    s_load_thread = NULL;
    
    EPUB_DEBUG("=== Thread exiting ===");
}

