/* Public function to open a file */
void ui_file_screen_open_file(const char *filepath, ui_fs_file_type_t file_type)
{
    if (!filepath) {
        return;
    }

    /* Switch to file screen */
    _ui_screen_change(&ui_file_screen, LV_SCR_LOAD_ANIM_FADE_ON, 0, 0, &ui_file_screen_screen_init);

    /* Load the file */
    ui_file_screen_load_file(filepath, file_type);
}

/* Load file into screen */
static void ui_file_screen_load_file(const char *filepath, ui_fs_file_type_t file_type)
{
    /* Cleanup previous state */
    if (file_screen_state.ebook_reader) {
        ui_ebook_reader_cleanup(file_screen_state.ebook_reader);
        file_screen_state.ebook_reader = NULL;
    }

    if (file_screen_state.current_filepath) {
        lv_free(file_screen_state.current_filepath);
        file_screen_state.current_filepath = NULL;
    }

    /* Store file info */
    file_screen_state.current_filepath = lv_malloc(strlen(filepath) + 1);
    if (file_screen_state.current_filepath) {
        strcpy(file_screen_state.current_filepath, filepath);
    }
    file_screen_state.file_type = file_type;
    file_screen_state.is_ebook_mode = false;

    /* Build full path */
    char full_path[512];
    if (filepath[0] == '/') {
        /* Absolute path */
        strncpy(full_path, filepath, sizeof(full_path) - 1);
        full_path[sizeof(full_path) - 1] = '\0';
    } else {
        /* Relative to FS_PATH */
        snprintf(full_path, sizeof(full_path), "%s/%s", TF_CARD_ROOT_PATH, filepath);
    }

    /* Hide image by default */
    if (ui_file_screen_Image4) {
        lv_obj_add_flag(ui_file_screen_Image4, LV_OBJ_FLAG_HIDDEN);
    }

    /* Check file type and load accordingly */
    if (file_type == UI_FS_FILE_TYPE_FILE_EPUB || file_type == UI_FS_FILE_TYPE_FILE_TEXT) {
        /* ============================================
         * ASYNC EBOOK LOADING (方案3：最优方案)
         * ============================================ */
        
        file_screen_state.is_ebook_mode = true;
        
        /* Check if already loading */
        if (s_is_loading) {
            LV_LOG_WARN("Already loading a file, please wait");
            update_loading_status("Already loading...");
            return;
        }
        
        /* Cancel any previous loading */
        s_cancel_loading = false;
        
        /* Show loading UI */
        show_loading_ui(true);
        update_loading_status("Loading EPUB...");
        
        /* Prepare task data for background thread */
        load_task_data_t *task = tal_malloc(sizeof(load_task_data_t));
        if (!task) {
            LV_LOG_ERROR("Failed to allocate task data");
            show_loading_ui(false);
            if (ui_file_screen_Image4) {
                lv_obj_remove_flag(ui_file_screen_Image4, LV_OBJ_FLAG_HIDDEN);
                lv_image_set_src(ui_file_screen_Image4, &ui_img_image_floder_wallpaper_png);
            }
            return;
        }
        
        /* Copy file paths to task */
        strncpy(task->filepath, filepath, sizeof(task->filepath) - 1);
        task->filepath[sizeof(task->filepath) - 1] = '\0';
        
        strncpy(task->full_path, full_path, sizeof(task->full_path) - 1);
        task->full_path[sizeof(task->full_path) - 1] = '\0';
        
        task->file_type = file_type;
        task->container = ui_file_screen_file_container;
        
        /* Create and start background loading thread */
        s_is_loading = true;
        
        THREAD_CFG_T thread_cfg = {
            .priority = THREAD_PRIO_2,      // Lower priority than UI
            .stackDepth = 16384,            // 16KB stack for EPUB extraction
            .thrdname = "epub_load"
        };
        
        OPERATE_RET ret = tal_thread_create_and_start(
            &s_load_thread,
            NULL,
            NULL,
            file_load_thread_func,
            task,
            &thread_cfg
        );
        
        if (ret != OPRT_OK) {
            LV_LOG_ERROR("Failed to create loading thread: %d", ret);
            tal_free(task);
            s_is_loading = false;
            show_loading_ui(false);
            
            /* Fallback: Show error image */
            if (ui_file_screen_Image4) {
                lv_obj_remove_flag(ui_file_screen_Image4, LV_OBJ_FLAG_HIDDEN);
                lv_image_set_src(ui_file_screen_Image4, &ui_img_image_floder_wallpaper_png);
            }
        } else {
            EPUB_DEBUG("Loading thread created successfully, handle=%p", s_load_thread);
        }
        
    } else if (file_type == UI_FS_FILE_TYPE_FILE_PNG) {
        /* Image mode - load image */
        file_screen_state.is_ebook_mode = false;
        if (ui_file_screen_Image4) {
            lv_obj_clear_flag(ui_file_screen_Image4, LV_OBJ_FLAG_HIDDEN);
            /* Try to load image from file path */
            lv_image_set_src(ui_file_screen_Image4, full_path);
        }
    } else {
        /* Unknown type, show default image */
        if (ui_file_screen_Image4) {
            lv_obj_clear_flag(ui_file_screen_Image4, LV_OBJ_FLAG_HIDDEN);
            lv_image_set_src(ui_file_screen_Image4, &ui_img_image_floder_wallpaper_png);
        }
    }
}

