/* Keyboard handler - handles ESC to exit */
static void ui_file_screen_keyboard_esc(void)
{
    /* If loading, cancel it */
    if (s_is_loading) {
        LV_LOG_USER("ESC pressed: cancelling file loading");
        s_cancel_loading = true;
        update_loading_status("Cancelling...");
        
        /* Wait briefly for cancellation */
        int wait_count = 0;
        while (s_is_loading && wait_count < 5) {
            tal_system_sleep(100);
            wait_count++;
        }
        
        show_loading_ui(false);
    }
    
    /* Exit file screen and return to folder screen */
    _ui_screen_change(&ui_floder_screen, LV_SCR_LOAD_ANIM_FADE_ON, 0, 0, &ui_floder_screen_screen_init);
    LV_LOG_USER("ui_file_screen_keyboard_esc: exited file screen");
}

