/* Keyboard handler - main handler that routes key events */
static void ui_file_screen_keyboard_handler(lv_event_t *e)
{
    lv_event_code_t code = lv_event_get_code(e);
    if (code != LV_EVENT_KEY) {
        return;
    }

    lv_key_t key = lv_event_get_key(e);

    /* Route keys to ebook reader if in ebook mode */
    if (file_screen_state.is_ebook_mode && file_screen_state.ebook_reader) {
        ui_ebook_reader_handle_key(file_screen_state.ebook_reader, key);
        return;
    }

    /* Handle non-ebook navigation */
    switch (key) {
        case LV_KEY_UP:
        case LV_KEY_LEFT:
            ui_file_screen_keyboard_prev_page();
            LV_LOG_USER("ui_file_screen_keyboard_handler: UP or LEFT");
            break;
        case LV_KEY_DOWN:
        case LV_KEY_RIGHT:
            ui_file_screen_keyboard_next_page();
            LV_LOG_USER("ui_file_screen_keyboard_handler: DOWN or RIGHT");
            break;
        case LV_KEY_ENTER:
            ui_file_screen_keyboard_enter();
            LV_LOG_USER("ui_file_screen_keyboard_handler: ENTER");
            break;
        case LV_KEY_ESC:
            ui_file_screen_keyboard_esc();
            LV_LOG_USER("ui_file_screen_keyboard_handler: ESC");
            break;
        default:
            break;
    }
}

// event functions
void ui_event_file_screen(lv_event_t * e)
{
    lv_event_code_t event_code = lv_event_get_code(e);

    if(event_code == LV_EVENT_SCREEN_LOADED) {
        ui_file_screen_loaded(e);
        // Initialize keyboard group
        ui_file_screen_keyboard_group_init();
    } else if(event_code == LV_EVENT_SCREEN_UNLOADED) {
        // Cleanup keyboard group
        ui_file_screen_keyboard_group_destroy();
    }
}

// build functions

void ui_file_screen_screen_init(void)
{
    ui_file_screen = lv_obj_create(NULL);
    lv_obj_remove_flag(ui_file_screen, LV_OBJ_FLAG_SCROLLABLE);      /// Flags
    lv_obj_add_flag(ui_file_screen, LV_OBJ_FLAG_CLICKABLE);          /// Make screen focusable for keyboard
    /* Prevent default ENTER behavior on screen - we handle it in keyboard handler */
    lv_obj_clear_flag(ui_file_screen, LV_OBJ_FLAG_SCROLLABLE);

    ui_file_screen_file_container = lv_obj_create(ui_file_screen);
    lv_obj_remove_style_all(ui_file_screen_file_container);
    lv_obj_set_width(ui_file_screen_file_container, lv_pct(100));
    lv_obj_set_height(ui_file_screen_file_container, lv_pct(100));
    lv_obj_set_align(ui_file_screen_file_container, LV_ALIGN_CENTER);
    lv_obj_remove_flag(ui_file_screen_file_container, LV_OBJ_FLAG_CLICKABLE | LV_OBJ_FLAG_SCROLLABLE);      /// Flags
    /* Prevent container from processing keyboard events - screen handles them */
    lv_obj_clear_flag(ui_file_screen_file_container, LV_OBJ_FLAG_CLICKABLE);

    ui_file_screen_Image4 = lv_image_create(ui_file_screen);
    lv_image_set_src(ui_file_screen_Image4, &ui_img_image_floder_wallpaper_png);
    lv_obj_set_width(ui_file_screen_Image4, LV_SIZE_CONTENT);   /// 1
    lv_obj_set_height(ui_file_screen_Image4, LV_SIZE_CONTENT);    /// 1
    lv_obj_set_align(ui_file_screen_Image4, LV_ALIGN_CENTER);
    lv_obj_add_flag(ui_file_screen_Image4, LV_OBJ_FLAG_CLICKABLE);     /// Flags
    lv_obj_remove_flag(ui_file_screen_Image4, LV_OBJ_FLAG_SCROLLABLE);      /// Flags

    lv_obj_add_event_cb(ui_file_screen, ui_event_file_screen, LV_EVENT_ALL, NULL);
    /* Add keyboard handler - handle ENTER before any default behavior */
    lv_obj_add_event_cb(ui_file_screen, ui_file_screen_keyboard_handler, LV_EVENT_KEY, NULL);
    /* Add click handler to intercept ENTER-triggered clicks in ebook mode */
    lv_obj_add_event_cb(ui_file_screen, ui_file_screen_click_handler, LV_EVENT_CLICKED, NULL);
}

/* Keyboard group initialization */
static void ui_file_screen_keyboard_group_init(void)
{
    if (sg_keyboard_group) {
        lv_group_remove_all_objs(sg_keyboard_group);
        lv_indev_set_group(lv_indev_get_next(NULL), sg_keyboard_group);
        return;
    }

    sg_keyboard_group = lv_group_create();
    if (NULL == sg_keyboard_group) {
        LV_LOG_ERROR("ui_file_screen_keyboard_group_init: failed to create group");
        return;
    }

    lv_group_add_obj(sg_keyboard_group, ui_file_screen);
    /* Set the screen as the focused object */
    lv_group_focus_obj(ui_file_screen);
    lv_indev_set_group(lv_indev_get_next(NULL), sg_keyboard_group);
}

/* Keyboard group cleanup */
static void ui_file_screen_keyboard_group_destroy(void)
{
    if (!sg_keyboard_group) {
        return;
    }

    lv_group_delete(sg_keyboard_group);
    sg_keyboard_group = NULL;
}

void ui_file_screen_screen_destroy(void)
{
    LV_LOG_USER("ui_file_screen_screen_destroy: cleaning up");
    
    /* Cancel any ongoing loading */
    if (s_is_loading) {
        LV_LOG_WARN("Cancelling ongoing file loading");
        s_cancel_loading = true;
        
        /* Wait briefly for thread to finish (don't block too long) */
        int wait_count = 0;
        while (s_is_loading && wait_count < 10) {
            tal_system_sleep(100); // Sleep 100ms
            wait_count++;
        }
        
        if (s_is_loading) {
            LV_LOG_ERROR("Loading thread did not finish in time");
        }
    }
    
    /* Cleanup loading UI */
    cleanup_loading_ui();
    
    /* Cleanup ebook reader */
    if (file_screen_state.ebook_reader) {
        ui_ebook_reader_cleanup(file_screen_state.ebook_reader);
        file_screen_state.ebook_reader = NULL;
    }

    if (file_screen_state.current_filepath) {
        lv_free(file_screen_state.current_filepath);
        file_screen_state.current_filepath = NULL;
    }

    if(ui_file_screen) lv_obj_del(ui_file_screen);

    // NULL screen variables
    ui_file_screen = NULL;
    ui_file_screen_file_container = NULL;
    ui_file_screen_Image4 = NULL;
    
    LV_LOG_USER("ui_file_screen_screen_destroy: complete");
}
